queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?riskname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRisks ?child ; p:hasBank_Products ?parent . } GROUP BY ?child }
  ?child p:RiskName ?riskname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bank_Products } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?riskname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRisks ?child ; p:hasBank_Products ?parent . } GROUP BY ?child }
  ?child p:RiskName ?riskname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Bank_Products } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?productname ?riskname WHERE {
  ?bank_products_risks a :Bank_Products_Risks .
  ?risks a :Risks .
  ?bank_products_risks p:hasRisks ?risks .
  ?bank_products a :Bank_Products .
  ?bank_products_risks p:hasBank_Products ?bank_products .
  ?bank_products p:ProductName ?productname .
  ?risks p:RiskName ?riskname .
} }
}
